                {
                    convertedRightOperand = TypeConverterHelper.Convert(rightOperandString, leftOperandType);
                }
                catch (FormatException)
                {
                    // Keep original rightOperand and let comparable evaluation decide.
                }
                catch (InvalidCastException)
                {
